      let t = x >>> 16;
      if (t !== 0) {
        x = t;
        r += 16;
      }
      t = x >> 8;
      if (t !== 0) {
        x = t;
        r += 8;
      }
      t = x >> 4;
      if (t !== 0) {
        x = t;
        r += 4;
      }
      t = x >> 2;
      if (t !== 0) {
        x = t;
        r += 2;
      }
      t = x >> 1;
      if (t !== 0) {
        x = t;
        r += 1;
      }
      return r;
